const body = $input.first().json.body || $input.first().json;
const validTypes = ['interview','survey','support','note','review','document','other'];
const item = {
  id:        body.id        || `res_${Date.now()}`,
  type:      validTypes.includes(body.type) ? body.type : 'other',
  source:    body.source    || 'manual',
  content:   (body.content || body.text || body.transcript || '').slice(0,8000),
  segment:   body.segment   || 'unknown',
  date:      body.date      || new Date().toISOString().slice(0,10),
  author:    body.author    || 'anonymous',
  tags:      body.tags      || [],
  metadata:  body.metadata  || {},
};
return [{ json: item }];

