const item = $('Normalise Input').first().json;
let ai;
try { ai = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); }
catch { ai = {}; }
return [{ json: { ...item, summary: ai.summary||'', themes: [...(item.tags||[]),...(ai.themes||[])], sentiment: ai.sentiment||'neutral', key_insight: ai.key_insight||'', problems_mentioned: ai.problems_mentioned||[], product_areas: ai.product_areas||[], ai_confidence: ai.confidence||0, added_to_repository_at: new Date().toISOString() } }];

